from array import array
hits = array('i', [0]) * 2000000000
squares = sorted([x**2 for x in range(15000)])
reverse_squares = sorted(list(set([int(str(a)[::-1]) for a in squares])))
hits[0] = 999 #don't count zero
for a in squares:
    for b in reverse_squares:
        hits[a+b] += 1
for q in range(0,22):
    print(hits.index(q), end=", ")
